function tryParseJson(s) {
  if (typeof s !== "string") return null;
  try { return JSON.parse(s); } catch { return null; }
}

function extractJsonFromText(s) {
  if (typeof s !== "string") return null;
  const a = s.indexOf("{");
  const b = s.lastIndexOf("}");
  if (a >= 0 && b > a) return tryParseJson(s.slice(a, b + 1));
  return null;
}

function getPayload(j) {
  if (j && typeof j === "object" && j.required_response_structure) return j;

  const cands = [
    j?.output,
    j?.text,
    j?.message?.content,
    j?.choices?.[0]?.message?.content
  ].filter(Boolean);

  for (const c of cands) {
    const parsed = tryParseJson(c) || extractJsonFromText(c);
    if (parsed && parsed.required_response_structure) return parsed;
  }

  throw new Error("Could not parse canonical tender JSON.");
}

function asStringArray(v) {
  return Array.isArray(v) ? v.map(x => String(x).trim()).filter(Boolean) : [];
}

function safeNodeJson(nodeName) {
  try {
    return $(nodeName).first()?.json || null;
  } catch {
    return null;
  }
}

const tender = getPayload($json);

// Pull extracted upload metadata
const uploadMeta = safeNodeJson("Extract Tender ID + Classify Upload");
const extractedTenderId = uploadMeta?.tender_id ?? null;

// Keep AI value if present, otherwise fall back to extracted tender_id
tender.rfp_id = tender.rfp_id ?? extractedTenderId ?? null;

// Optional cleanup: if AI returned empty string, still fall back
if (typeof tender.rfp_id === "string" && !tender.rfp_id.trim()) {
  tender.rfp_id = extractedTenderId ?? null;
}

tender.rfp_title = tender.rfp_title ?? null;
tender.client_org = tender.client_org ?? null;
tender.procurement_type = tender.procurement_type ?? null;
tender.project_number_cost_centre = tender.project_number_cost_centre ?? null;

tender.submission_deadline = tender.submission_deadline || { date: null, time_local: null, timezone: null };
tender.submission_method = tender.submission_method || { channel: null, details: null };

tender.formatting_requirements = tender.formatting_requirements || {
  page_limit: null,
  font_size: null,
  language: null,
  file_format: null,
  other_constraints: []
};
tender.formatting_requirements.other_constraints = asStringArray(tender.formatting_requirements.other_constraints);

tender.overall_expectations = asStringArray(tender.overall_expectations);
tender.open_questions = asStringArray(tender.open_questions);

tender.evaluation_criteria = Array.isArray(tender.evaluation_criteria) ? tender.evaluation_criteria : [];
tender.work_packages = Array.isArray(tender.work_packages) ? tender.work_packages : [];
tender.compliance_checklist = Array.isArray(tender.compliance_checklist) ? tender.compliance_checklist : [];

tender.required_response_structure = Array.isArray(tender.required_response_structure)
  ? tender.required_response_structure.map((s, idx) => ({
      section_id: s.section_id || `S${idx + 1}`,
      order: Number.isFinite(Number(s.order)) ? Number(s.order) : idx + 1,
      title: s.title || `Section ${idx + 1}`,
      is_mandatory: typeof s.is_mandatory === "boolean" ? s.is_mandatory : null,
      page_or_word_limit: s.page_or_word_limit ?? null,
      required_content: asStringArray(s.required_content),
      evaluation_alignment: asStringArray(s.evaluation_alignment),
      source_quotes: asStringArray(s.source_quotes),
    }))
  : [];

if (!tender.required_response_structure.length) {
  throw new Error("Canonical tender JSON missing required_response_structure.");
}

const existingIds = new Set();
tender.required_response_structure = tender.required_response_structure.map((s, idx) => {
  let id = s.section_id || `S${idx + 1}`;
  if (existingIds.has(id)) id = `S${idx + 1}`;
  existingIds.add(id);
  return { ...s, section_id: id, order: idx + 1 };
});

tender.scoring_structure = Array.isArray(tender.scoring_structure)
  ? tender.scoring_structure.map((g, idx) => ({
      group_code: g.group_code ? String(g.group_code).trim() : `G${idx + 1}`,
      group_title: g.group_title ? String(g.group_title).trim() : `Scoring Group ${idx + 1}`,
      group_weight: Number.isFinite(Number(g.group_weight)) ? Number(g.group_weight) : null,
      parent_section_id: g.parent_section_id ? String(g.parent_section_id).trim() : null,
      items: Array.isArray(g.items) ? g.items.map((it, j) => ({
        criterion_code: it.criterion_code ? String(it.criterion_code).trim() : `${g.group_code || `G${idx + 1}`}.${j + 1}`,
        criterion_title: it.criterion_title ? String(it.criterion_title).trim() : `Criterion ${j + 1}`,
        weight: Number.isFinite(Number(it.weight)) ? Number(it.weight) : null,
        best_response_format: it.best_response_format ?? null,
        likely_evidence_needed: asStringArray(it.likely_evidence_needed),
      })) : [],
      source_quotes: asStringArray(g.source_quotes),
    }))
  : [];

return [{ json: tender }];

const base = $items("Code in JavaScript1")[0]?.json;
if (!base) throw new Error("Missing base item from Code in JavaScript1.");

const created = $("Create sheet").first().json;
const sheetId = created.sheetId;

if (!sheetId) throw new Error("Create sheet did not return sheetId.");

return [{
  json: { ...base, sheetId }
}];

parameters.text:
=You are a senior proposal strategist designing a concise global writer brief.

Use ONLY COMPACT_BRIEF.
Do not invent facts.
Do not restate the full tender.
Be concise, specific, and practical.

Output MUST be a SINGLE valid JSON object with EXACTLY TWO top-level keys:
1) "insights_block"
2) "section_insights"

SCHEMA:

{
  "insights_block": {
    "executive_takeaways": string[],
    "proposal_strategy": string[],
    "win_themes": [
      {
        "theme": string,
        "so_what": string,
        "proof_needed": string[]
      }
    ],
    "risks": [
      {
        "risk": string,
        "impact": string,
        "mitigation": string,
        "owner": string
      }
    ],
    "go_no_go_flags": string[],
    "clarification_questions_global": [
      {
        "question": string,
        "why": string,
        "blocks": string[]
      }
    ],
    "critical_human_contributions": [
      {
        "area": string,
        "who_to_ask": string,
        "questions_to_ask": string[],
        "artifacts_needed": string[]
      }
    ]
  },
  "section_insights": {
    "<SECTION_ID>": {
      "section_summary": string,
      "score_weight_total": number|null,
      "score_logic": string[],
      "what_evaluators_want": string[],
      "human_inputs_needed": string[],
      "questions_for_humans": string[],
      "evidence_to_pull": string[],
      "drafting_outline": string[]
    }
  }
}

RULES
- The keys of section_insights MUST EXACTLY match required_response_structure[].section_id.
- Keep output compact.
- Make win themes specific to actual work packages, scoring priorities, and section content.
- Do not propose reusable blocks.
- Do not produce criterion-level guidance here.
- Do not propose tables here.

COMPACT_BRIEF:
{{ JSON.stringify($json.compact_brief) }}

parameters.jsCode:
function tryParseJson(s) {
  if (typeof s !== "string") return null;
  try { return JSON.parse(s); } catch { return null; }
}

function extractJsonFromText(s) {
  if (typeof s !== "string") return null;
  const start = s.indexOf("{");
  const end = s.lastIndexOf("}");
  if (start >= 0 && end > start) return tryParseJson(s.slice(start, end + 1));
  return null;
}

function getAgentPayload(j) {
  if (j && typeof j === "object" && (j.insights_block || j.section_insights)) return j;

  const candidates = [];
  if (typeof j === "string") candidates.push(j);
  if (j?.output) candidates.push(j.output);
  if (j?.text) candidates.push(j.text);
  if (j?.message?.content) candidates.push(j.message.content);
  if (j?.choices?.[0]?.message?.content) candidates.push(j.choices[0].message.content);

  for (const c of candidates) {
    const parsed = tryParseJson(c) || extractJsonFromText(c);
    if (parsed && (parsed.insights_block || parsed.section_insights)) return parsed;
  }

  throw new Error("Could not parse AI Agent1 output into JSON.");
}

function asArray(v) {
  return Array.isArray(v) ? v : [];
}

const parsed = getAgentPayload($json);

if (!parsed.insights_block) throw new Error("AI Agent1 output missing insights_block");
if (!parsed.section_insights) throw new Error("AI Agent1 output missing section_insights");

const canonical = $items("Build AI Agent Input")[0]?.json?.tender;
if (!canonical) throw new Error("Missing canonical tender from Build AI Agent Input");

const canonSorted = [...(canonical.required_response_structure || [])]
  .sort((a, b) => (a.order || 999) - (b.order || 999));

const canonIds = canonSorted.map(s => s.section_id);
const returnedIds = Object.keys(parsed.section_insights || {});

const sameSet =
  returnedIds.length === canonIds.length &&
  canonIds.every(id => returnedIds.includes(id));

if (!sameSet) {
  const returnedEntries = Object.entries(parsed.section_insights || {});
  if (returnedEntries.length === canonSorted.length) {
    const remapped = {};
    for (let i = 0; i < canonSorted.length; i++) {
      remapped[canonSorted[i].section_id] = returnedEntries[i][1];
    }
    parsed.section_insights = remapped;
  } else {
    throw new Error(`section_insights keys mismatch. Expected ${canonIds.join(", ")} but got ${returnedIds.join(", ")}`);
  }
}

parsed.insights_block.executive_takeaways = asArray(parsed.insights_block.executive_takeaways);
parsed.insights_block.proposal_strategy = asArray(parsed.insights_block.proposal_strategy);
parsed.insights_block.win_themes = asArray(parsed.insights_block.win_themes);
parsed.insights_block.risks = asArray(parsed.insights_block.risks);
parsed.insights_block.go_no_go_flags = asArray(parsed.insights_block.go_no_go_flags);
parsed.insights_block.clarification_questions_global = asArray(parsed.insights_block.clarification_questions_global);
parsed.insights_block.critical_human_contributions = asArray(parsed.insights_block.critical_human_contributions);

for (const s of Object.values(parsed.section_insights || {})) {
  s.score_logic = asArray(s.score_logic);
  s.what_evaluators_want = asArray(s.what_evaluators_want);
  s.human_inputs_needed = asArray(s.human_inputs_needed);
  s.questions_for_humans = asArray(s.questions_for_humans);
  s.evidence_to_pull = asArray(s.evidence_to_pull);
  s.drafting_outline = asArray(s.drafting_outline);
  if (s.score_weight_total != null && Number.isFinite(Number(s.score_weight_total))) {
    s.score_weight_total = Number(s.score_weight_total);
  } else {
    s.score_weight_total = null;
  }
}

return [{ json: { tender_insights: parsed } }];

function pickSectionScoring(scoringStructure, sectionId) {
  return (Array.isArray(scoringStructure) ? scoringStructure : [])
    .filter(g => g.parent_section_id === sectionId)
    .map(g => ({
      group_code: g.group_code,
      group_title: g.group_title,
      group_weight: g.group_weight,
      items: Array.isArray(g.items) ? g.items.map(it => ({
        criterion_code: it.criterion_code,
        criterion_title: it.criterion_title,
        weight: it.weight,
        best_response_format: it.best_response_format
      })) : []
    }));
}

const tender = $json;

const compact_brief = {
  rfp_id: tender.rfp_id ?? null,
  rfp_title: tender.rfp_title ?? null,
  client_org: tender.client_org ?? null,
  procurement_type: tender.procurement_type ?? null,
  formatting_requirements: tender.formatting_requirements ?? null,
  overall_expectations: tender.overall_expectations ?? [],
  evaluation_criteria: (tender.evaluation_criteria || []).map(x => ({
    criterion: x.criterion,
    weight: x.weight,
    description: x.description
  })),
  required_response_structure: (tender.required_response_structure || []).map(s => ({
    section_id: s.section_id,
    order: s.order,
    title: s.title,
    page_or_word_limit: s.page_or_word_limit,
    required_content: s.required_content,
    evaluation_alignment: s.evaluation_alignment,
    scoring_groups: pickSectionScoring(tender.scoring_structure, s.section_id)
  })),
  work_packages: (tender.work_packages || []).map(wp => ({
    wp_no: wp.wp_no,
    title: wp.title,
    objective: wp.objective,
    deliverables: (wp.deliverables || []).map(d => ({
      deliverable_no: d.deliverable_no,
      title: d.title,
      bottom_line: d.bottom_line
    }))
  })),
  personnel_requirements: {
    roles: (tender.personnel_requirements?.roles || []).map(r => ({
      role_name: r.role_name,
      role_code: r.role_code,
      qualifications: r.qualifications,
      input_spec_days: r.input_spec_days
    }))
  },
  costing_and_travel_rules: tender.costing_and_travel_rules ?? { rules: [], input_spec_table_notes: [] },
  scoring_structure: tender.scoring_structure || [],
  open_questions: tender.open_questions || []
};

const static_text_blocks = {
  company_profile: {
    block_key: "company_profile",
    approved_text: "[PASTE APPROVED SCIO COMPANY PROFILE TEXT HERE]"
  },
  key_references: {
    block_key: "key_references",
    approved_text: "[PASTE APPROVED SCIO REFERENCE HIGHLIGHTS HERE]"
  },
  backstopping: {
    block_key: "backstopping",
    approved_text: "[PASTE APPROVED SCIO BACKSTOPPING TEXT HERE]"
  },
  competency_matrix_intro: {
    block_key: "competency_matrix_intro",
    approved_text: "[PASTE APPROVED COMPETENCY MATRIX INTRO HERE]"
  }
};

return [{
  json: {
    tender,
    compact_brief,
    static_text_blocks
  }
}];

const items = $input.all().map(i => i.json);

const canonical = items.find(x => x.required_response_structure && x.formatting_requirements);
const insights = items.find(x => x.tender_insights)?.tender_insights;

if (!canonical) throw new Error("Missing canonical item from merge.");
if (!insights) throw new Error("Missing tender_insights item from merge.");

return [{
  json: {
    ...canonical,
    tender_insights: insights
  }
}];

function extractCodesFromAlignment(arr) {
  const codes = new Set();
  for (const line of Array.isArray(arr) ? arr : []) {
    const matches = String(line).match(/\b\d+\.\d+(?:\.\d+)?\b/g) || [];
    for (const m of matches) codes.add(m);
  }
  return [...codes];
}

function scoringForSection(scoringStructure, section) {
  const groups = Array.isArray(scoringStructure) ? scoringStructure : [];
  const sectionId = section.section_id || null;
  const title = String(section.title || '').toLowerCase();
  const alignmentCodes = extractCodesFromAlignment(section.evaluation_alignment || []);

  let matched = groups.filter(g => g.parent_section_id && g.parent_section_id === sectionId);
  if (matched.length) return matched;

  matched = groups.filter(g => {
    const code = String(g.group_code || '');

    if (alignmentCodes.some(c => code === c || code.startsWith(c + '.'))) return true;

    if ((title.includes('technical') || title.includes('methodological')) &&
        ['1.1','1.2','1.3','1.4','1.5'].some(prefix => code === prefix || code.startsWith(prefix + '.'))) {
      return true;
    }

    if ((title.includes('project management') || title.includes('personnel assignment')) &&
        (code === '1.6' || code.startsWith('1.6.'))) {
      return true;
    }

    if ((title.includes('personnel') || title.includes('cv')) &&
        (code === '2' || code.startsWith('2.'))) {
      return true;
    }

    return false;
  });

  return matched;
}

const tender = $json;
const section = tender.required_response_structure ?? {};
const section_id = section.section_id ?? tender.section_id ?? null;

const sheetId = tender.sheetId ?? tender.sheet_id ?? null;
const merge_key =
  tender.merge_key ??
  (sheetId && section_id ? `${sheetId}::${section_id}` : (section_id ?? null));

const scoringStructure = Array.isArray(tender.scoring_structure) ? tender.scoring_structure : [];
const scoring_for_section = scoringForSection(scoringStructure, section);
const section_insight_fallback = tender.tender_insights?.section_insights?.[section_id] ?? null;

const agent2_input = {
  rfp_meta: {
    rfp_id: tender.rfp_id ?? null,
    rfp_title: tender.rfp_title ?? null,
    client_org: tender.client_org ?? null,
    procurement_type: tender.procurement_type ?? null,
  },

  formatting_requirements: tender.formatting_requirements ?? null,
  evaluation_criteria: tender.evaluation_criteria ?? [],
  scoring_structure_for_section: scoring_for_section,

  section: {
    section_id: section.section_id ?? section_id,
    title: section.title ?? null,
    order: section.order ?? null,
    is_mandatory: section.is_mandatory ?? null,
    page_or_word_limit: section.page_or_word_limit ?? null,
    required_content: section.required_content ?? [],
    evaluation_alignment: section.evaluation_alignment ?? [],
    source_quotes: section.source_quotes ?? [],
  },

  global_insights: tender.tender_insights?.insights_block ?? null,
  section_insight_fallback_from_agent1: section_insight_fallback
};

return {
  json: {
    ...tender,
    merge_key,
    agent2_input
  }
};

function tryParseJson(s) {
  if (typeof s !== "string") return null;
  try {
    return JSON.parse(s);
  } catch {
    try {
      return JSON.parse(s.replace(/\r?\n/g, "\\n"));
    } catch {
      return null;
    }
  }
}

function extractJson(s) {
  if (typeof s !== "string") return null;
  const start = s.indexOf("{");
  const end = s.lastIndexOf("}");
  if (start >= 0 && end > start) return tryParseJson(s.slice(start, end + 1));
  return null;
}

function toList(v) {
  if (Array.isArray(v)) return v;
  if (typeof v === "string") {
    return v
      .split(/\r?\n/)
      .map(line => line.replace(/^\s*(?:•|-|\*|\d+[\).\:-])\s*/, "").trim())
      .filter(Boolean);
  }
  return [];
}

function ensureFiveQuestions(list, requiredContent) {
  let out = Array.isArray(list) ? list.slice(0, 5) : [];
  if (out.length < 5) {
    const rc = Array.isArray(requiredContent) ? requiredContent : [];
    for (let i = out.length; i < 5; i++) {
      const topic = rc[i] || rc[0] || "this section";
      out.push(`What specific information, evidence, or decisions do we need to provide about: ${topic}?`);
    }
  }
  return out;
}

function deriveScoreWeightTotal(scoringGroups) {
  const nums = (Array.isArray(scoringGroups) ? scoringGroups : [])
    .map(g => Number(g.group_weight))
    .filter(n => Number.isFinite(n));
  if (!nums.length) return null;
  return nums.reduce((a, b) => a + b, 0);
}

function deriveSectionHeading(section, scoringGroups, fallbackWeight) {
  const order = section.order ?? '';
  const title = section.title || 'Section';
  const weight = fallbackWeight ?? deriveScoreWeightTotal(scoringGroups);
  return weight != null
    ? `${order}. ${title} (${weight}%)`
    : `${order}. ${title}`;
}

function deriveSubsectionHeadings(scoringGroups) {
  const out = [];
  for (const g of Array.isArray(scoringGroups) ? scoringGroups : []) {
    const gWeight = Number.isFinite(Number(g.group_weight)) ? ` (${Number(g.group_weight)}%)` : '';
    if (g.group_code || g.group_title) {
      out.push({
        heading: `${g.group_code || ''} ${g.group_title || ''}${gWeight}`.trim(),
        criterion_codes: Array.isArray(g.items) ? g.items.map(it => it.criterion_code).filter(Boolean) : []
      });
    }
  }
  return out;
}

function deriveCriterionGuidance(scoringGroups) {
  const out = [];
  for (const g of Array.isArray(scoringGroups) ? scoringGroups : []) {
    for (const it of Array.isArray(g.items) ? g.items : []) {
      out.push({
        criterion_code: it.criterion_code || '',
        criterion_title: it.criterion_title || '',
        weight: Number.isFinite(Number(it.weight)) ? Number(it.weight) : null,
        what_to_prove: [
          `Directly answer the scored requirement for ${it.criterion_code || 'this criterion'}.`,
          `Provide concrete evidence, examples, or structure that makes the response easy to score.`,
          `Show explicit fit to the tender's requested content rather than generic capability claims.`
        ],
        what_not_to_do: [
          'Do not restate the ToR without showing how the team will deliver.',
          'Do not bury scored points in generic narrative or unsupported claims.'
        ],
        best_format: it.best_response_format || 'narrative'
      });
    }
  }
  return out;
}

function deriveSummary(section) {
  const title = section.title || 'section';
  const content = Array.isArray(section.required_content) ? section.required_content.slice(0, 4) : [];
  if (!content.length) return `Writer-facing guidance for ${title}.`;
  return `Write this section to directly cover: ${content.join('; ')}.`;
}

function deriveEvaluatorWants(section, scoringGroups) {
  const fromCriteria = [];
  for (const g of Array.isArray(scoringGroups) ? scoringGroups : []) {
    for (const it of Array.isArray(g.items) ? g.items : []) {
      if (it.criterion_title) fromCriteria.push(String(it.criterion_title));
    }
  }
  if (fromCriteria.length) return fromCriteria.slice(0, 8);

  return (Array.isArray(section.required_content) ? section.required_content : [])
    .map(x => String(x).replace(/\s*\(\d+\.\d+(?:\.\d+)?\)\s*/g, '').trim())
    .filter(Boolean)
    .slice(0, 8);
}

function deriveInputs(section) {
  return (Array.isArray(section.required_content) ? section.required_content : [])
    .map(x => `Input needed for: ${String(x).replace(/\s*\(\d+\.\d+(?:\.\d+)?\)\s*/g, '').trim()}`)
    .slice(0, 6);
}

function deriveEvidence(section, scoringGroups) {
  const evidence = [];
  for (const g of Array.isArray(scoringGroups) ? scoringGroups : []) {
    for (const it of Array.isArray(g.items) ? g.items : []) {
      for (const e of Array.isArray(it.likely_evidence_needed) ? it.likely_evidence_needed : []) {
        evidence.push(String(e));
      }
    }
  }
  if (evidence.length) return [...new Set(evidence)].slice(0, 8);

  return [
    'Relevant project examples',
    'Operational plans, schedules, or matrices',
    'Named stakeholder or delivery assumptions',
    'Concrete proof that scored criteria are addressed'
  ];
}

function deriveOutline(section, scoringGroups) {
  const subs = deriveSubsectionHeadings(scoringGroups).map(x => x.heading);
  if (subs.length) return subs;
  return (Array.isArray(section.required_content) ? section.required_content : [])
    .map(x => String(x).replace(/\s*\(\d+\.\d+(?:\.\d+)?\)\s*/g, '').trim())
    .filter(Boolean);
}

function deriveWinThemes(section) {
  const title = String(section.title || '');
  if (/technical|methodological/i.test(title)) {
    return [
      'Show a delivery model that turns organisational development needs into concrete products, processes, and implementation tools.',
      'Make YPP and IAC logic operational, not conceptual, with clear sequencing and outputs.'
    ];
  }
  if (/project management|personnel assignment/i.test(title)) {
    return [
      'Show credible delivery control, coordination discipline, and role-task sequencing.',
      'Make staffing feasibility obvious through timing, ownership, and backstopping clarity.'
    ];
  }
  if (/personnel|cv/i.test(title)) {
    return [
      'Make expert fit easy to score by surfacing qualifications, Africa experience, and role relevance immediately.',
      'Use each CV to prove criterion fit, not just biography.'
    ];
  }
  if (/financial/i.test(title)) {
    return [
      'Show exact compliance with pricing instructions and consistency with the proposed delivery model.'
    ];
  }
  return [];
}

function deriveHighlightBox(section) {
