  const evalToken = /(technical\s+evaluation|evaluation\s+grid|assessment\s+grid|evaluation\s+criteria)/i.test(nameLower);
  const hasEvaluationWord = /(^|[^a-z0-9])evaluation([^a-z0-9]|$)/i.test(nameLower);
