  const isTor =
    /(^|[^a-z0-9])tor([^a-z0-9]|$)/i.test(nameLower) ||
    /terms?\s+of\s+reference/i.test(nameLower) ||
    /scope\s+of\s+work/i.test(nameLower) ||
    /request\s+for\s+expression\s+of\s+interest/i.test(nameLower) ||
