  const isEval =
    /(technical\s+evaluation|evaluation\s+grid|assessment\s+grid|evaluation\s+criteria)/i.test(nameLower) ||
    /(^|[^a-z0-9])evaluation([^a-z0-9]|$)/i.test(nameLower) ||
    /\bscore(card|sheet)?\b/i.test(nameLower);

  if (isTor && !isEval) return "TOR";
  if (isEval && !isTor) return "EVAL";
  if (isTor && isEval) return "TOR";
