function block(title, body) {
  if (!body) return null;
  return `${title}\n${body}`;
}

function parseJsonSafe(s) {
  if (!s) return [];
  if (Array.isArray(s)) return s;
  try { return JSON.parse(s); } catch { return []; }
}

function tableTemplate(t) {
  if (!t || !Array.isArray(t.columns)) return '';
  return [
    t.table_title || 'Table',
    `Purpose: ${t.purpose || ''}`,
    '',
    '| ' + t.columns.join(' | ') + ' |',
    '| ' + t.columns.map(() => '---').join(' | ') + ' |',
    '| ' + t.columns.map(() => ' ').join(' | ') + ' |'
  ].join('\n');
}

const staticBlocks = {
  backstopping: "[PASTE APPROVED SCIO BACKSTOPPING TEXT HERE]",
  competency_matrix_intro: "[PASTE APPROVED COMPETENCY MATRIX INTRO HERE]",
  key_references: "[PASTE APPROVED SHORT REFERENCE HIGHLIGHTS HERE]"
};

function renderReusableBlocks(blocks) {
  if (!Array.isArray(blocks) || !blocks.length) return '';
  return blocks.map(b => {
    const key = b.block_key;
    const title = `Reusable Block: ${key}`;
    const text = staticBlocks[key] || `[MISSING APPROVED TEXT FOR ${key}]`;
    const note = b.placement_note ? `Placement Note: ${b.placement_note}\n\n` : '';
    return `${title}\n${note}${text}`;
  }).join('\n\n');
}

function sectionBlock(row) {
  const chunks = [];

  chunks.push(row.section_heading || `${row.order || ''}. ${row.title || row.section_id || 'Section'}`);

  if (row.section_summary) chunks.push(block('Section Summary', row.section_summary));
  if (row.subsection_headings) chunks.push(block('Subsection Headings', row.subsection_headings));
  if (row.section_win_themes) chunks.push(block('Section Win Themes', row.section_win_themes));

  if (row.highlight_box_title || row.highlight_box_body) {
    chunks.push(block(`Highlight Box${row.highlight_box_title ? `: ${row.highlight_box_title}` : ''}`, row.highlight_box_body || ''));
  }

  if (row.what_evaluators_want) chunks.push(block('What Evaluators Want', row.what_evaluators_want));
  if (row.human_inputs_needed) chunks.push(block('Human Inputs Needed', row.human_inputs_needed));
  if (row.questions_for_humans) chunks.push(block('Questions for Humans', row.questions_for_humans));
  if (row.evidence_to_pull) chunks.push(block('Evidence To Pull', row.evidence_to_pull));
  if (row.drafting_outline) chunks.push(block('Drafting Outline', row.drafting_outline));
  if (row.evaluation_alignment) chunks.push(block('Evaluation Alignment', row.evaluation_alignment));

  const criterionGuidance = parseJsonSafe(row.criterion_level_guidance_json);
  if (criterionGuidance.length) {
    const text = criterionGuidance.map(c => {
      const prove = Array.isArray(c.what_to_prove) ? c.what_to_prove.map(x => `  - Prove: ${x}`).join('\n') : '';
      const avoid = Array.isArray(c.what_not_to_do) ? c.what_not_to_do.map(x => `  - Avoid: ${x}`).join('\n') : '';
      const head = `${c.criterion_code || ''} ${c.criterion_title || ''}${c.weight != null ? ` (${c.weight}%)` : ''}`.trim();
      return [head, prove, avoid, c.best_format ? `  - Best format: ${c.best_format}` : ''].filter(Boolean).join('\n');
    }).join('\n\n');
    chunks.push(block('Criterion-Level Guidance', text));
  }

  const tables = parseJsonSafe(row.suggested_tables_json);
  if (tables.length) {
    chunks.push(block('Suggested Tables', tables.map(tableTemplate).join('\n\n')));
  }

  const reusableBlocks = parseJsonSafe(row.reusable_blocks_json);
  const renderedReusableBlocks = renderReusableBlocks(reusableBlocks);
  if (renderedReusableBlocks) {
    chunks.push(block('Predefined Text Blocks To Insert', renderedReusableBlocks));
  }

  return chunks.filter(Boolean).join('\n\n');
}

const upstream =
  $items('Build Google Docs Replace Requests')[0]?.json ??
  $items('Merge Doc Context')[0]?.json;

const rows = upstream?.section_rows_written || [];

if (!rows.length) {
  throw new Error('No section rows available for document assembly.');
