const combinedSectionText = rows
  .sort((a, b) => Number(a.order || 9999) - Number(b.order || 9999))
  .map(sectionBlock)
  .join('\n\n==================================================\n\n');

return [{
  json: {
    ...upstream,
    combinedSectionText
  }
}];

