function extractCodesFromAlignment(arr) {
  const codes = new Set();
  for (const line of Array.isArray(arr) ? arr : []) {
    const matches = String(line).match(/\b\d+\.\d+(?:\.\d+)?\b/g) || [];
    for (const m of matches) codes.add(m);
  }
  return [...codes];
}

function scoringForSection(scoringStructure, section) {
  const groups = Array.isArray(scoringStructure) ? scoringStructure : [];
  const sectionId = section.section_id || null;
  const title = String(section.title || '').toLowerCase();
  const alignmentCodes = extractCodesFromAlignment(section.evaluation_alignment || []);

  let matched = groups.filter(g => g.parent_section_id && g.parent_section_id === sectionId);
  if (matched.length) return matched;

  matched = groups.filter(g => {
    const code = String(g.group_code || '');

    if (alignmentCodes.some(c => code === c || code.startsWith(c + '.'))) return true;

    if ((title.includes('technical') || title.includes('methodological')) &&
        ['1.1','1.2','1.3','1.4','1.5'].some(prefix => code === prefix || code.startsWith(prefix + '.'))) {
      return true;
    }

    if ((title.includes('project management') || title.includes('personnel assignment')) &&
        (code === '1.6' || code.startsWith('1.6.'))) {
      return true;
    }

    if ((title.includes('personnel') || title.includes('cv')) &&
        (code === '2' || code.startsWith('2.'))) {
      return true;
    }

    return false;
  });

  return matched;
}

