    return `${theme}${so ? ` — ${so}` : ""}${proof ? ` (Proof: ${proof})` : ""}`;
  });
}

function formatRisks(risks) {
  return bulletFromObjects(risks, (r) => {
    const risk = r.risk ? String(r.risk) : "Risk";
    const impact = r.impact ? String(r.impact) : "";
    const mit = r.mitigation ? String(r.mitigation) : "";
    const owner = r.owner ? String(r.owner) : "";
    const parts = [];
    if (impact) parts.push(`impact: ${impact}`);
    if (mit) parts.push(`mitigation: ${mit}`);
    if (owner) parts.push(`owner: ${owner}`);
    return `${risk}${parts.length ? ` — ${parts.join(" | ")}` : ""}`;
  });
}

function formatCriticalContrib(cc) {
  return bulletFromObjects(cc, (x) => {
    const area = x.area ? String(x.area) : "Area";
    const who = x.who_to_ask ? String(x.who_to_ask) : "";
    const qs = Array.isArray(x.questions_to_ask) ? x.questions_to_ask.join("; ") : "";
    return `${area}${who ? ` (Ask: ${who})` : ""}${qs ? ` — Questions: ${qs}` : ""}`;
