  const torToken = /(^|[^a-z0-9])tor([^a-z0-9]|$)/i.test(nameLower);
  return torToken || /terms?\s+of\s+reference|scope\s+of\s+work/i.test(nameLower);
}

function isEval(nameLower) {
  const evalToken = /(technical\s+evaluation|evaluation\s+grid|assessment\s+grid|evaluation\s+criteria)/i.test(nameLower);
  const hasEvaluationWord = /(^|[^a-z0-9])evaluation([^a-z0-9]|$)/i.test(nameLower);
  return evalToken || hasEvaluationWord;
}

const candidates = items.filter(f => belongs(norm(f.name)));

const tor = candidates.find(f => isTor(norm(f.name))) || null;
const evalGrid = candidates.find(f => isEval(norm(f.name)) && !isTor(norm(f.name))) || null;

return [{
  json: {
    tender_id,
    tor_file: tor ? { id: tor.id, name: tor.name } : null,
    eval_file: evalGrid ? { id: evalGrid.id, name: evalGrid.name } : null,
    candidates: candidates.map(c => c.name),
  }
}];

const file = {
  id: $json.id,
  name: $json.name || "",
  mimeType: $json.mimeType || "",
  parents: $json.parents || [],
};

const lower = file.name.toLowerCase().trim();

// Support:
// - 03-81323001
// - 81323001
// - 0002021012
// - leading numeric token followed by _, space, -, ., or end
const hyphenMatch = file.name.match(/(?:^|[^\d])(\d{2}-\d{7,12})(?=$|[_\s.\-])/);
const plainMatch  = file.name.match(/(?:^|[^\d])(\d{8,12})(?=$|[_\s.\-])/);
const leadingMatch = file.name.match(/^(\d{6,12})(?=$|[_\s.\-])/);

const tender_id =
  (hyphenMatch ? hyphenMatch[1] : null) ||
  (leadingMatch ? leadingMatch[1] : null) ||
  (plainMatch ? plainMatch[1] : null) ||
  null;

function classify(nameLower) {
  const isTor =
    /(^|[^a-z0-9])tor([^a-z0-9]|$)/i.test(nameLower) ||
    /terms?\s+of\s+reference/i.test(nameLower) ||
    /scope\s+of\s+work/i.test(nameLower) ||
    /request\s+for\s+expression\s+of\s+interest/i.test(nameLower) ||
    /expression\s+of\s+interest/i.test(nameLower) ||
    /request\s+for\s+proposal/i.test(nameLower) ||
    /\beoi\b/i.test(nameLower) ||
    /\brfp\b/i.test(nameLower);

  const isEval =
    /(technical\s+evaluation|evaluation\s+grid|assessment\s+grid|evaluation\s+criteria)/i.test(nameLower) ||
    /(^|[^a-z0-9])evaluation([^a-z0-9]|$)/i.test(nameLower) ||
    /\bscore(card|sheet)?\b/i.test(nameLower);

  if (isTor && !isEval) return "TOR";
  if (isEval && !isTor) return "EVAL";
  if (isTor && isEval) return "TOR";
  return "UNKNOWN";
}

return [{
  json: {
    file,
    tender_id,
    upload_type: classify(lower),
    inbox_folder_id: file.parents?.[0] || null
  }
}];

function safeNodeJson(nodeName) {
  try {
    const item = $(nodeName).first();
    return item?.json || null;
  } catch {
    return null;
  }
}

function asText(v) {
  return (v == null ? "" : String(v)).trim();
}

// Current incoming item(s)
const current = $input.all().map(i => i.json);

// Fallback named nodes
const torExtractNode = safeNodeJson("Extract from File2");
const evalExtractNode = safeNodeJson("Extract from File1");
const torDownload = safeNodeJson("Download file1");
const evalDownload = safeNodeJson("Download file");
const finder = safeNodeJson("Code in JavaScript7");
const uploadMeta = safeNodeJson("Extract Tender ID + Classify Upload");

// Prefer actual incoming extracted text first
let tor_text = "";
let evaluation_grid_text = "";

// Look at incoming items from Merge3 / direct execution
for (const item of current) {
  const txt = asText(item?.text);
  if (!txt) continue;

  const title = asText(item?.info?.Title || item?.fileName || item?.name).toLowerCase();

  const looksEval =
    /(technical\s+evaluation|evaluation\s+grid|assessment\s+grid|evaluation\s+criteria|score(card|sheet)?)/i.test(title);

  if (looksEval && !evaluation_grid_text) {
    evaluation_grid_text = txt;
  } else if (!tor_text) {
    tor_text = txt;
  }
}

// Fallback to named extraction nodes if current input did not provide enough
if (!tor_text) {
  tor_text = asText(torExtractNode?.text);
}
if (!evaluation_grid_text) {
  evaluation_grid_text = asText(evalExtractNode?.text);
}

// Final guard
if (!tor_text) {
  throw new Error("Missing TOR text. No usable extracted TOR text was found in current input or Extract from File2.");
}

return [{
  json: {
    tender_id: finder?.tender_id || uploadMeta?.tender_id || null,
    tor_file: finder?.tor_file || (torDownload ? { id: torDownload.id, name: torDownload.name } : null),
    eval_file: finder?.eval_file || (evalDownload ? { id: evalDownload.id, name: evalDownload.name } : null),
    tor_text,
    evaluation_grid_text,
    has_evaluation_grid: !!evaluation_grid_text
  }
}];

const rows = $items('Code in JavaScript2').map(i => i.json);

if (!rows.length) {
  throw new Error('No rows received from Code in JavaScript2.');
}

const orderedRows = rows
  .filter(r => r.section_id)
  .sort((a, b) => Number(a.order || 9999) - Number(b.order || 9999));

return [{
  json: {
    section_rows_written: orderedRows
  }
}];

function asArray(v) {
  return Array.isArray(v) ? v : [];
}

function bullets(arr) {
  const a = asArray(arr).map(x => String(x).trim()).filter(Boolean);
  return a.length ? a.map(x => `• ${x}`).join('\n') : '';
}

function bulletsFromObjects(arr, formatter) {
  const a = asArray(arr);
  return a.length ? a.map(x => `• ${formatter(x)}`).join('\n') : '';
}

const tender = $json;
const insights = tender.tender_insights?.insights_block || {};

const submissionDeadline = [
  tender.submission_deadline?.date,
  tender.submission_deadline?.time_local,
  tender.submission_deadline?.timezone
].filter(Boolean).join(' ');

const submissionMethod = [
  tender.submission_method?.channel,
  tender.submission_method?.details
].filter(Boolean).join(' — ');

const templateTokens = {
  '{{RFP_ID}}': tender.rfp_id || '',
  '{{RFP_TITLE}}': tender.rfp_title || '',
  '{{CLIENT_ORG}}': tender.client_org || '',
  '{{PROCUREMENT_TYPE}}': tender.procurement_type || '',
  '{{SUBMISSION_DEADLINE}}': submissionDeadline,
  '{{SUBMISSION_METHOD}}': submissionMethod,
  '{{EXECUTIVE_TAKEAWAYS}}': bullets(insights.executive_takeaways),
  '{{WIN_THEMES}}': bulletsFromObjects(insights.win_themes, (t) => {
    const proof = Array.isArray(t.proof_needed) && t.proof_needed.length
      ? ` (Proof needed: ${t.proof_needed.join('; ')})`
      : '';
    return `${t.theme || 'Theme'} — ${t.so_what || ''}${proof}`.trim();
  }),
  '{{RISKS}}': bulletsFromObjects(insights.risks, (r) => {
    const parts = [];
    if (r.impact) parts.push(`impact: ${r.impact}`);
    if (r.mitigation) parts.push(`mitigation: ${r.mitigation}`);
    if (r.owner) parts.push(`owner: ${r.owner}`);
    return `${r.risk || 'Risk'}${parts.length ? ` — ${parts.join(' | ')}` : ''}`;
  }),
  '{{GO_NO_GO_FLAGS}}': bullets(insights.go_no_go_flags),
  '{{CLARIFICATION_QUESTIONS}}': bulletsFromObjects(insights.clarification_questions_global, (q) => {
    return `${q.question || ''}${q.why ? ` — ${q.why}` : ''}`;
  }),
  '{{CRITICAL_HUMAN_CONTRIBUTIONS}}': bulletsFromObjects(insights.critical_human_contributions, (c) => {
    const ask = c.who_to_ask ? `Ask: ${c.who_to_ask}` : '';
    const qs = Array.isArray(c.questions_to_ask) && c.questions_to_ask.length
      ? ` Questions: ${c.questions_to_ask.join('; ')}`
      : '';
    return `${c.area || 'Area'}${ask ? ` — ${ask}` : ''}${qs}`;
  }),
  '{{SECTION_BLOCKS}}': '__SECTION_BLOCKS__'
};

const proposal_doc_name = [
  tender.rfp_id || 'NO-RFP-ID',
  tender.rfp_title || 'Proposal Pack'
].join(' - ').slice(0, 180);

return [{
  json: {
    tender,
    templateTokens,
    proposal_doc_name
  }
}];

const copied = $json;
const upstream = $items('Merge Doc Context')[0].json;

const documentId = copied.id || copied.fileId || copied.documentId;
if (!documentId) {
  throw new Error('Copied template did not return a document id.');
}

const rows = upstream.section_rows_written || [];
if (!rows.length) {
  throw new Error('No section rows available.');
}

const first = rows[0];

function safe(v) {
  return v == null ? '' : String(v);
}

const staticBlocks = {
  company_profile: "[PASTE APPROVED SCIO COMPANY PROFILE TEXT HERE]",
  key_references: "[PASTE APPROVED SCIO REFERENCE HIGHLIGHTS HERE]"
};

const tokenMap = {
  '{{RFP_ID}}': safe(first.rfp_id),
  '{{RFP_TITLE}}': safe(first.rfp_title),
  '{{CLIENT_ORG}}': safe(first.client_org),
  '{{PROCUREMENT_TYPE}}': safe(first.procurement_type),
  '{{SUBMISSION_DEADLINE}}': '',
  '{{SUBMISSION_METHOD}}': '',
  '{{EXECUTIVE_TAKEAWAYS}}': safe(first.executive_takeaways),
  '{{WIN_THEMES}}': safe(first.win_themes),
  '{{RISKS}}': safe(first.risks),
  '{{GO_NO_GO_FLAGS}}': safe(first.go_no_go_flags),
  '{{CLARIFICATION_QUESTIONS}}': '',
  '{{CRITICAL_HUMAN_CONTRIBUTIONS}}': safe(first.critical_human_contributions),
  '{{PROPOSAL_STRATEGY}}': safe(first.proposal_strategy),
  '{{COMPANY_PROFILE}}': staticBlocks.company_profile,
  '{{KEY_REFERENCES}}': staticBlocks.key_references,
  '{{SECTION_BLOCKS}}': '__SECTION_BLOCKS__',
  '{{HUMAN_INPUT_REGISTER}}': '__HUMAN_INPUT_REGISTER__'
};

const proposal_doc_name = `${safe(first.rfp_id) || 'NO-RFP-ID'} - ${safe(first.rfp_title) || 'Proposal Pack'}`
  .slice(0, 180);

const replace_requests = Object.entries(tokenMap).map(([placeholder, replacement]) => ({
  replaceAllText: {
    containsText: {
      text: placeholder,
      matchCase: true
    },
    replaceText: replacement
  }
}));

return [{
  json: {
    ...upstream,
    documentId,
    proposal_doc_name,
    templateTokens: tokenMap,
    replace_requests
  }
}];

const copied = $json;
const upstream = $items('Merge Doc Context')[0].json;

const documentId = copied.id || copied.fileId || copied.documentId;
if (!documentId) {
  throw new Error('Copied template did not return a document id.');
}

const rows = upstream.section_rows_written || [];
if (!rows.length) {
  throw new Error('No section rows available.');
}

const first = rows[0];

function safe(v) {
  return v == null ? '' : String(v);
}

const tokenMap = {
  '{{RFP_ID}}': safe(first.rfp_id),
  '{{RFP_TITLE}}': safe(first.rfp_title),
  '{{CLIENT_ORG}}': safe(first.client_org),
  '{{PROCUREMENT_TYPE}}': safe(first.procurement_type),
  '{{SUBMISSION_DEADLINE}}': '',
  '{{SUBMISSION_METHOD}}': '',
  '{{EXECUTIVE_TAKEAWAYS}}': safe(first.executive_takeaways),
  '{{WIN_THEMES}}': safe(first.win_themes),
  '{{RISKS}}': safe(first.risks),
  '{{GO_NO_GO_FLAGS}}': safe(first.go_no_go_flags),
  '{{CLARIFICATION_QUESTIONS}}': '',
  '{{CRITICAL_HUMAN_CONTRIBUTIONS}}': safe(first.critical_human_contributions),
  '{{SECTION_BLOCKS}}': '__SECTION_BLOCKS__'
};

const proposal_doc_name = `${safe(first.rfp_id) || 'NO-RFP-ID'} - ${safe(first.rfp_title) || 'Proposal Pack'}`
  .slice(0, 180);

const replace_requests = Object.entries(tokenMap).map(([placeholder, replacement]) => ({
  replaceAllText: {
    containsText: {
      text: placeholder,
      matchCase: true
    },
    replaceText: replacement
  }
}));

return [{
  json: {
    ...upstream,
    documentId,
    proposal_doc_name,
    templateTokens: tokenMap,
    replace_requests
  }
}];

return [{
  json: {
    documentId: $json.documentId,
    isArray: Array.isArray($json.replace_requests),
    firstRequest: $json.replace_requests?.[0] || null,
    requestCount: $json.replace_requests?.length || 0
  }
}];

function block(title, body) {
  if (!body) return null;
  return `${title}\n${body}`;
}

function parseJsonSafe(s) {
  if (!s) return [];
  if (Array.isArray(s)) return s;
  try { return JSON.parse(s); } catch { return []; }
}

function tableTemplate(t) {
  if (!t || !Array.isArray(t.columns)) return '';
  return [
    t.table_title || 'Table',
    `Purpose: ${t.purpose || ''}`,
    '',
    '| ' + t.columns.join(' | ') + ' |',
    '| ' + t.columns.map(() => '---').join(' | ') + ' |',
    '| ' + t.columns.map(() => ' ').join(' | ') + ' |'
  ].join('\n');
}

const staticBlocks = {
  backstopping: "[PASTE APPROVED SCIO BACKSTOPPING TEXT HERE]",
  competency_matrix_intro: "[PASTE APPROVED COMPETENCY MATRIX INTRO HERE]",
  key_references: "[PASTE APPROVED SHORT REFERENCE HIGHLIGHTS HERE]"
};

function renderReusableBlocks(blocks) {
  if (!Array.isArray(blocks) || !blocks.length) return '';
  return blocks.map(b => {
    const key = b.block_key;
    const title = `Reusable Block: ${key}`;
    const text = staticBlocks[key] || `[MISSING APPROVED TEXT FOR ${key}]`;
    const note = b.placement_note ? `Placement Note: ${b.placement_note}\n\n` : '';
    return `${title}\n${note}${text}`;
  }).join('\n\n');
}

function sectionBlock(row) {
  const chunks = [];

  chunks.push(row.section_heading || `${row.order || ''}. ${row.title || row.section_id || 'Section'}`);

  if (row.section_summary) chunks.push(block('Section Summary', row.section_summary));
  if (row.subsection_headings) chunks.push(block('Subsection Headings', row.subsection_headings));
  if (row.section_win_themes) chunks.push(block('Section Win Themes', row.section_win_themes));

  if (row.highlight_box_title || row.highlight_box_body) {
    chunks.push(block(`Highlight Box${row.highlight_box_title ? `: ${row.highlight_box_title}` : ''}`, row.highlight_box_body || ''));
  }

  if (row.what_evaluators_want) chunks.push(block('What Evaluators Want', row.what_evaluators_want));
  if (row.human_inputs_needed) chunks.push(block('Human Inputs Needed', row.human_inputs_needed));
  if (row.questions_for_humans) chunks.push(block('Questions for Humans', row.questions_for_humans));
  if (row.evidence_to_pull) chunks.push(block('Evidence To Pull', row.evidence_to_pull));
  if (row.drafting_outline) chunks.push(block('Drafting Outline', row.drafting_outline));
  if (row.evaluation_alignment) chunks.push(block('Evaluation Alignment', row.evaluation_alignment));

  const criterionGuidance = parseJsonSafe(row.criterion_level_guidance_json);
  if (criterionGuidance.length) {
    const text = criterionGuidance.map(c => {
      const prove = Array.isArray(c.what_to_prove) ? c.what_to_prove.map(x => `  - Prove: ${x}`).join('\n') : '';
      const avoid = Array.isArray(c.what_not_to_do) ? c.what_not_to_do.map(x => `  - Avoid: ${x}`).join('\n') : '';
      const head = `${c.criterion_code || ''} ${c.criterion_title || ''}${c.weight != null ? ` (${c.weight}%)` : ''}`.trim();
      return [head, prove, avoid, c.best_format ? `  - Best format: ${c.best_format}` : ''].filter(Boolean).join('\n');
    }).join('\n\n');
    chunks.push(block('Criterion-Level Guidance', text));
  }

  const tables = parseJsonSafe(row.suggested_tables_json);
  if (tables.length) {
    chunks.push(block('Suggested Tables', tables.map(tableTemplate).join('\n\n')));
  }

  const reusableBlocks = parseJsonSafe(row.reusable_blocks_json);
  const renderedReusableBlocks = renderReusableBlocks(reusableBlocks);
  if (renderedReusableBlocks) {
    chunks.push(block('Predefined Text Blocks To Insert', renderedReusableBlocks));
  }

  return chunks.filter(Boolean).join('\n\n');
}

const upstream =
  $items('Build Google Docs Replace Requests')[0]?.json ??
  $items('Merge Doc Context')[0]?.json;

const rows = upstream?.section_rows_written || [];

if (!rows.length) {
  throw new Error('No section rows available for document assembly.');
}

const combinedSectionText = rows
  .sort((a, b) => Number(a.order || 9999) - Number(b.order || 9999))
  .map(sectionBlock)
  .join('\n\n==================================================\n\n');

return [{
  json: {
    ...upstream,
    combinedSectionText
  }
}];

